const items = $input.all();
const item = items[0].json;
const isTelegram = item.message !== undefined;

let platform, userId, chatId, text, name;

if (isTelegram) {
  platform = "telegram";
  userId = String(item.message.from.id);
  chatId = item.message.chat.id;
  text = item.message.text || "";
  name = item.message.from.first_name + " " + (item.message.from.last_name || "");
} else {
  platform = "whatsapp";
  userId = item.From;
  chatId = item.From;
  text = item.Body || "";
  name = item.ProfileName || "Cliente";
}

const sessionId = platform + "_" + userId;
return [{
  json: { platform, userId, chatId, text: text.trim(), name: name.trim(), sessionId }
}];

const sessionItem = $items("Get Bot Session")[0]?.json || {};
const sucursales = $items("Get Sucursales Validas").map(i => i.json);
const servicios = $items("Get Servicios").map(i => i.json);
const empleados = $items("Get Empleados").map(i => i.json);

const input = $items("Parse Input")[0].json;

const current_step = sessionItem.current_step || "1";
const sucursal_id = sessionItem.data?.sucursal_id || "";

const sucursalesList = sucursales.map(s => `- ID: ${s.id} | Nombre: ${s.nombre}`).join("
");

let serviciosList = "";
if (sucursal_id) {
    serviciosList = servicios.filter(s => String(s.sucursal_id) === String(sucursal_id))
                             .map(s => `- ID: ${s.id} | ${s.nombre} ($${s.precio_base}) - ${s.duracion_aprox_minutos} min`).join("
");
} else {
    sucursales.forEach(sucursal => {
        const servs = servicios.filter(s => String(s.sucursal_id) === String(sucursal.id));
        serviciosList += `
--- Servicios Sucursal ${sucursal.nombre} (ID: ${sucursal.id}) ---
`;
        serviciosList += servs.map(s => `- ID: ${s.id} | ${s.nombre} ($${s.precio_base}) - ${s.duracion_aprox_minutos} min`).join("
");
    });
}

let empleadosList = "";
if (sucursal_id) {
    empleadosList = empleados.filter(e => String(e.sucursal_id) === String(sucursal_id))
                             .map(e => `- ID: ${e.id} | ${e.nombre} (${e.especialidad})`).join("
");
} else {
    sucursales.forEach(sucursal => {
        const emps = empleados.filter(e => String(e.sucursal_id) === String(sucursal.id));
        empleadosList += `
--- Barberos Sucursal ${sucursal.nombre} (ID: ${sucursal.id}) ---
`;
        empleadosList += emps.map(e => `- ID: ${e.id} | ${e.nombre} (${e.especialidad})`).join("
");
    });
}

const prompt = `Eres el asistente virtual de Kyros Barber, una barberia premium. Ayudas a clientes a agendar citas de forma amigable y profesional.

FLUJO DE 14 PASOS:
1. BIENVENIDA - Saluda calurosamente.
2. SUCURSAL - Muestra la lista de sucursales disponibles y pide que elija una.
3. SERVICIOS - Muestra catalogo de servicios de la sucursal seleccionada y pide que elija.
4. PRECIOS - Muestra desglose: Subtotal + Comision + Total a pagar
5. DETALLES - Pide descripcion opcional del corte deseado
6. NOMBRE - Solicita nombre completo del cliente
7. TELEFONO - Solicita telefono de 10 digitos (obligatorio)
8. EMAIL - Solicita email para enviar recibos de pago
9. FECHA - Muestra dias disponibles en formato carrusel de botones
10. HORA - Calcula disponibilidad y muestra slots disponibles
11. EMPLEADO - Muestra lista de barberos disponibles o opcion Sin preferencia
12. RESUMEN - Muestra tarjeta visual con: Cliente, Telefono, Fecha, Hora, Servicios, Barbero, Total y Sucursal
13. PAGO - Confirma que redirigira a pago.
14. CONFIRMACION - Mensaje de exito, confirmacion de cita y boton para Nueva Cita

ESTADO ACTUAL DEL USUARIO:
- Sesion: ${input.sessionId}
- Cliente: ${input.name}
- Mensaje recibido: ${input.text}
- PASO ACTUAL: ${current_step}
- SUCURSAL ELEGIDA ID: ${sucursal_id}

SUCURSALES VÁLIDAS SELECCIONABLES:
${sucursalesList || "Sin datos"}

SERVICIOS DISPONIBLES EN SISTEMA:
${serviciosList || "Sin datos"}

BARBEROS DISPONIBLES EN SISTEMA:
${empleadosList || "Sin datos"}

INSTRUCCIONES CRITÍCAS:
- El usuario está en el paso: ${current_step}.
- Si la sucursal elegida está en blanco, el paso DEBE ser 1 o 2 y tu objetivo es que elijan una de la lista de SUCURSALES VALIDAS.
- Si el cliente te indica una sucursal, INMEDIATAMENTE incluye los servicios de ESA sucursal en tu respuesta.
- Guarda su ID en la propiedad "sucursal_id" de tu JSON siempre.
- NO uses markdown para responder fuera del JSON. DEBES devolver UNICAMENTE un objeto JSON en bruto con este exacto formato:

{
  "message": "<aqui tu respuesta al usuario, mostrando los servicios si acaban de elegir sucursal>",
  "new_step": "<numero del paso al que avanzamos>",
  "sucursal_id": "<ID de la sucursal seleccionada>"
}`;

return [{ json: { ...input, prompt } }];

const response = $input.first().json;
const candidates = response.candidates || [];
let text = candidates[0]?.content?.parts?.[0]?.text || "{}";

// Limpiar posibles backticks de markdown que el LLM devuelva
text = text.replace(/```json/g, '').replace(/```/g, '').trim();

let parsed = {};
try {
  parsed = JSON.parse(text);
} catch(e) {
  parsed = {
    message: "Disculpa, hubo un pequeño error al entender tu solicitud. ¿Me lo repites?",
    new_step: "1",
    sucursal_id: ""
  }
}

// Mantenemos el session_id o lo que se haya heredado
const inputData = $items("Build Prompt")[0].json;

return [{
  json: {
    ...inputData,
    aiResponse: parsed.message,
    new_step: String(parsed.new_step || "1"),
    sucursal_id: String(parsed.sucursal_id || "")
  }
}];

const input = $input.first().json;
const message = input.aiResponse;

// Para WhatsApp via webhook
const output = {
  To: input.chatId,
  Body: message
};

return [{ json: { output, platform: input.platform } }];
